final:
module lfsr (
    input wire clk,
    input wire rstn,
    output reg [4:0] lfsr_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
    if (~rstn)
        lfsr_out <= 5'b00001;
    else
        lfsr_out <= {lfsr_out[3:0], lfsr_out[4] ^ lfsr_out[2]};
end

endmodule
